26→func TestToolExecutor_InterfaceContract(t *testing.T) {
27→	exec := &stubExecutor{
28→		name: "test",
29→		tools: []ToolDef{
30→			{Name: "echo", Description: "echoes input", InputSchema: map[string]any{"type": "object"}},
31→		},
32→	}
33→
34→	if exec.Name() != "test" {
35→		t.Errorf("Name() = %q, want %q", exec.Name(), "test")
