  1→// Package mcpclient provides a Go client that speaks Model Context Protocol (MCP)
  2→// over stdio to downstream MCP servers running as subprocesses.
  3→//
  4→// Communication uses newline-delimited JSON-RPC 2.0 over the subprocess's
  5→// stdin (requests) and stdout (responses).
  6→package mcpclient
  7→
  8→import (
  9→	"bufio"
 10→	"context"
 11→	"encoding/json"
 12→	"fmt"
 13→	"io"
 14→	"os"
 15→	"os/exec"
 16→	"sync"
 17→	"sync/atomic"
 18→	"syscall"
 19→	"time"
 20→
 21→	"github.com/ALRubinger/aileron/core/mcp"
 22→	"github.com/ALRubinger/aileron/core/version"
 23→)
 24→
 25→// Client manages a connection to a single downstream MCP server subprocess.
 26→type Client struct {
 27→	name   string
 28→	cmd    *exec.Cmd
 29→	stdin  io.WriteCloser
 30→	stdout *bufio.Reader
 31→	mu     sync.Mutex // protects writes to stdin and reads from stdout
 32→	tools  []mcp.ToolDef
 33→	nextID int64
 34→}
 35→
 36→// JSON-RPC 2.0 wire types (internal).
 37→
 38→type jsonrpcRequest struct {
 39→	JSONRPC string `json:"jsonrpc"`
 40→	ID      any    `json:"id,omitempty"`
 41→	Method  string `json:"method"`
 42→	Params  any    `json:"params,omitempty"`
 43→}
 44→
 45→type jsonrpcResponse struct {
 46→	JSONRPC string          `json:"jsonrpc"`
 47→	ID      json.RawMessage `json:"id,omitempty"`
 48→	Result  json.RawMessage `json:"result,omitempty"`
 49→	Error   *jsonrpcError   `json:"error,omitempty"`
 50→}
 51→
 52→type jsonrpcError struct {
 53→	Code    int    `json:"code"`
 54→	Message string `json:"message"`
 55→}
 56→
 57→func (e *jsonrpcError) Error() string {
 58→	return fmt.Sprintf("jsonrpc error %d: %s", e.Code, e.Message)
 59→}
 60→
 61→// NewClient spawns a downstream MCP server as a subprocess and performs the
 62→// MCP initialize handshake. The command slice must contain at least the
 63→// program name; additional elements are passed as arguments. The env slice
 64→// is merged with os.Environ() so the subprocess inherits the current
 65→// environment plus any overrides.
 66→func NewClient(ctx context.Context, name string, command []string, env []string) (*Client, error) {
 67→	if len(command) == 0 {
 68→		return nil, fmt.Errorf("mcpclient: command must not be empty")
 69→	}
 70→
 71→	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
 72→	cmd.Env = append(os.Environ(), env...)
 73→	cmd.Stderr = os.Stderr
 74→
 75→	stdinPipe, err := cmd.StdinPipe()
 76→	if err != nil {
 77→		return nil, fmt.Errorf("mcpclient: stdin pipe: %w", err)
 78→	}
 79→
 80→	stdoutPipe, err := cmd.StdoutPipe()
 81→	if err != nil {
 82→		return nil, fmt.Errorf("mcpclient: stdout pipe: %w", err)
 83→	}
 84→
 85→	if err := cmd.Start(); err != nil {
 86→		return nil, fmt.Errorf("mcpclient: start %q: %w", command[0], err)
 87→	}
 88→
 89→	c := &Client{
 90→		name:   name,
 91→		cmd:    cmd,
 92→		stdin:  stdinPipe,
 93→		stdout: bufio.NewReader(stdoutPipe),
 94→		nextID: 1, // 1 is reserved for the initialize request
 95→	}
 96→
 97→	// --- MCP initialize handshake ---
 98→
 99→	initParams := map[string]any{
100→		"protocolVersion": "2024-11-05",
101→		"capabilities":    map[string]any{},
102→		"clientInfo": map[string]any{
103→			"name":    "aileron-gateway",
104→			"version": version.Version,
105→		},
106→	}
107→
108→	_, err = c.sendRequest("initialize", initParams)
109→	if err != nil {
110→		// Best-effort cleanup on failure.
111→		_ = c.Close()
112→		return nil, fmt.Errorf("mcpclient: initialize handshake: %w", err)
113→	}
114→
115→	// Send the initialized notification (no ID — it's a notification).
116→	if err := c.sendNotification("notifications/initialized"); err != nil {
117→		_ = c.Close()
118→		return nil, fmt.Errorf("mcpclient: initialized notification: %w", err)
119→	}
120→
121→	// Discover available tools.
122→	if _, err := c.DiscoverTools(ctx); err != nil {
123→		_ = c.Close()
124→		return nil, fmt.Errorf("mcpclient: discover tools: %w", err)
125→	}
126→
127→	return c, nil
128→}
129→
130→// DiscoverTools sends a tools/list request and caches the result.
131→func (c *Client) DiscoverTools(_ context.Context) ([]mcp.ToolDef, error) {
132→	raw, err := c.sendRequest("tools/list", nil)
133→	if err != nil {
134→		return nil, err
135→	}
136→
137→	var envelope struct {
138→		Tools []mcp.ToolDef `json:"tools"`
139→	}
140→	if err := json.Unmarshal(raw, &envelope); err != nil {
141→		return nil, fmt.Errorf("mcpclient: parse tools/list result: %w", err)
142→	}
143→
144→	c.tools = envelope.Tools
145→	return c.tools, nil
146→}
147→
148→// CallTool invokes a tool on the downstream MCP server by name.
149→func (c *Client) CallTool(_ context.Context, name string, arguments map[string]any) (*mcp.ToolResult, error) {
150→	params := map[string]any{
151→		"name":      name,
152→		"arguments": arguments,
153→	}
154→
155→	raw, err := c.sendRequest("tools/call", params)
156→	if err != nil {
157→		return nil, err
158→	}
159→
160→	var result mcp.ToolResult
161→	if err := json.Unmarshal(raw, &result); err != nil {
162→		return nil, fmt.Errorf("mcpclient: parse tools/call result: %w", err)
163→	}
164→
165→	return &result, nil
166→}
167→
168→// Tools returns the cached list of tools discovered from the server.
169→func (c *Client) Tools() []mcp.ToolDef {
170→	return c.tools
171→}
172→
173→// Name returns the human-readable name of this client connection.
174→func (c *Client) Name() string {
175→	return c.name
176→}
177→
178→// Close terminates the subprocess. It sends SIGTERM first, then SIGKILL
179→// after a 5-second timeout if the process hasn't exited.
180→func (c *Client) Close() error {
181→	if c.cmd == nil || c.cmd.Process == nil {
182→		return nil
183→	}
184→
185→	// Close stdin so the subprocess sees EOF.
186→	_ = c.stdin.Close()
187→
188→	// Send SIGTERM.
189→	if err := c.cmd.Process.Signal(syscall.SIGTERM); err != nil {
190→		// Process may have already exited; just wait.
191→		_ = c.cmd.Wait()
192→		return nil
193→	}
194→
195→	// Wait up to 5 seconds for graceful exit.
196→	done := make(chan error, 1)
197→	go func() {
198→		done <- c.cmd.Wait()
199→	}()
200→
201→	select {
202→	case err := <-done:
203→		return err
204→	case <-time.After(5 * time.Second):
205→		_ = c.cmd.Process.Kill()
206→		return <-done
207→	}
208→}
209→
210→// nextRequestID returns a monotonically increasing request ID.
211→func (c *Client) nextRequestID() int64 {
212→	return atomic.AddInt64(&c.nextID, 1)
213→}
214→
215→// sendRequest sends a JSON-RPC request and waits for the corresponding
216→// response. It returns the raw "result" field on success.
217→func (c *Client) sendRequest(method string, params any) (json.RawMessage, error) {
218→	c.mu.Lock()
219→	defer c.mu.Unlock()
220→
221→	id := c.nextRequestID()
222→	req := jsonrpcRequest{
223→		JSONRPC: "2.0",
224→		ID:      id,
225→		Method:  method,
226→		Params:  params,
227→	}
228→
229→	data, err := json.Marshal(req)
230→	if err != nil {
231→		return nil, fmt.Errorf("mcpclient: marshal request: %w", err)
232→	}
233→
234→	// Write newline-delimited JSON.
235→	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
236→		return nil, fmt.Errorf("mcpclient: write request: %w", err)
237→	}
238→
239→	resp, err := c.readResponse()
240→	if err != nil {
241→		return nil, err
242→	}
243→
244→	if resp.Error != nil {
245→		return nil, resp.Error
246→	}
247→
248→	return resp.Result, nil
249→}
250→
251→// sendNotification sends a JSON-RPC notification (no ID, no response expected).
252→func (c *Client) sendNotification(method string) error {
253→	c.mu.Lock()
254→	defer c.mu.Unlock()
255→
256→	req := jsonrpcRequest{
257→		JSONRPC: "2.0",
258→		Method:  method,
259→	}
260→
261→	data, err := json.Marshal(req)
262→	if err != nil {
263→		return fmt.Errorf("mcpclient: marshal notification: %w", err)
264→	}
265→
266→	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
267→		return fmt.Errorf("mcpclient: write notification: %w", err)
268→	}
269→
270→	return nil
271→}
272→
273→// readResponse reads one newline-delimited JSON line from the subprocess
274→// stdout and parses it as a JSON-RPC response.
275→func (c *Client) readResponse() (*jsonrpcResponse, error) {
276→	line, err := c.stdout.ReadBytes('\n')
277→	if err != nil {
278→		return nil, fmt.Errorf("mcpclient: read response: %w", err)
279→	}
280→
281→	var resp jsonrpcResponse
282→	if err := json.Unmarshal(line, &resp); err != nil {
283→		return nil, fmt.Errorf("mcpclient: parse response: %w (raw: %s)", err, string(line))
284→	}
285→
286→	return &resp, nil
287→}
