 1→package mem
 2→
 3→import (
 4→	"context"
 5→	"sync"
 6→
 7→	api "github.com/ALRubinger/aileron/core/api/gen"
 8→	"github.com/ALRubinger/aileron/core/store"
 9→)
10→
11→// MCPServerStore is a thread-safe in-memory implementation of store.MCPServerStore.
12→type MCPServerStore struct {
13→	mu      sync.RWMutex
14→	servers map[string]api.MCPServerConfig
15→}
16→
17→// NewMCPServerStore returns an empty in-memory MCP server store.
18→func NewMCPServerStore() *MCPServerStore {
19→	return &MCPServerStore{servers: make(map[string]api.MCPServerConfig)}
20→}
21→
22→func (s *MCPServerStore) Create(_ context.Context, server api.MCPServerConfig) error {
23→	s.mu.Lock()
24→	defer s.mu.Unlock()
25→	s.servers[*server.Id] = server
26→	return nil
27→}
28→
29→func (s *MCPServerStore) Get(_ context.Context, serverID string) (api.MCPServerConfig, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	srv, ok := s.servers[serverID]
33→	if !ok {
34→		return api.MCPServerConfig{}, &store.ErrNotFound{Entity: "mcp_server", ID: serverID}
35→	}
36→	return srv, nil
37→}
38→
39→func (s *MCPServerStore) List(_ context.Context, filter store.MCPServerFilter) ([]api.MCPServerConfig, error) {
40→	s.mu.RLock()
41→	defer s.mu.RUnlock()
42→	var result []api.MCPServerConfig
43→	for _, srv := range s.servers {
44→		if filter.Status != nil && (srv.Status == nil || *srv.Status != *filter.Status) {
45→			continue
46→		}
47→		result = append(result, srv)
48→	}
49→	return result, nil
50→}
51→
52→func (s *MCPServerStore) Update(_ context.Context, server api.MCPServerConfig) error {
53→	s.mu.Lock()
54→	defer s.mu.Unlock()
55→	if _, ok := s.servers[*server.Id]; !ok {
56→		return &store.ErrNotFound{Entity: "mcp_server", ID: *server.Id}
57→	}
58→	s.servers[*server.Id] = server
59→	return nil
60→}
61→
62→func (s *MCPServerStore) Delete(_ context.Context, serverID string) error {
63→	s.mu.Lock()
64→	defer s.mu.Unlock()
65→	if _, ok := s.servers[serverID]; !ok {
66→		return &store.ErrNotFound{Entity: "mcp_server", ID: serverID}
67→	}
68→	delete(s.servers, serverID)
69→	return nil
70→}
