 14→func TestMCPServerStore_CRUD(t *testing.T) {
 15→	ctx := context.Background()
 16→	s := mem.NewMCPServerStore()
 17→
 18→	// Create
 19→	srv := api.MCPServerConfig{
 20→		Id:      ptr("mcp_1"),
 21→		Name:    "test-server",
 22→		Command: []string{"npx", "-y", "@example/mcp-server"},
 23→		Status:  ptr(api.MCPServerConfigStatusStopped),
 24→	}
 25→	if err := s.Create(ctx, srv); err != nil {
 26→		t.Fatalf("Create: %v", err)
 27→	}
 28→
 29→	// Get
 30→	got, err := s.Get(ctx, "mcp_1")
 31→	if err != nil {
 32→		t.Fatalf("Get: %v", err)
 33→	}
 34→	if got.Name != "test-server" {
 35→		t.Errorf("Name = %q, want %q", got.Name, "test-server")
 36→	}
 37→	if len(got.Command) != 3 {
 38→		t.Errorf("Command length = %d, want 3", len(got.Command))
 39→	}
 40→
 41→	// List
 42→	list, err := s.List(ctx, store.MCPServerFilter{})
 43→	if err != nil {
 44→		t.Fatalf("List: %v", err)
 45→	}
 46→	if len(list) != 1 {
 47→		t.Fatalf("List length = %d, want 1", len(list))
 48→	}
 49→
 50→	// Update
 51→	srv.Name = "updated-server"
 52→	if err := s.Update(ctx, srv); err != nil {
 53→		t.Fatalf("Update: %v", err)
 54→	}
 55→	got, _ = s.Get(ctx, "mcp_1")
 56→	if got.Name != "updated-server" {
 57→		t.Errorf("Name after update = %q, want %q", got.Name, "updated-server")
 58→	}
 59→
 60→	// Delete
 61→	if err := s.Delete(ctx, "mcp_1"); err != nil {
 62→		t.Fatalf("Delete: %v", err)
 63→	}
 64→	_, err = s.Get(ctx, "mcp_1")
 65→	if err == nil {
 66→		t.Fatal("Get after Delete: expected error")
