124→func isErrNotFound(err error, target **store.ErrNotFound) bool {
125→	if err == nil {
126→		return false
127→	}
128→	var nf *store.ErrNotFound
129→	ok := false
130→	if e, isNF := err.(*store.ErrNotFound); isNF {
131→		nf = e
132→		ok = true
133→	}
134→	if ok && target != nil {
135→		*target = nf
136→	}
137→	return ok
138→}
