1305→// --- Marketplace ---
1306→
1307→func (s *apiServer) ListMarketplaceServers(w http.ResponseWriter, r *http.Request, params api.ListMarketplaceServersParams) {
1308→	ctx := r.Context()
1309→
1310→	var query string
1311→	if params.Q != nil {
1312→		query = *params.Q
1313→	}
1314→
1315→	servers, err := s.registryClient.Search(ctx, query)
1316→	if err != nil {
1317→		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
1318→		return
1319→	}
1320→
1321→	// Build a set of installed registry IDs for enrichment.
1322→	installed, _ := s.mcpServers.List(ctx, store.MCPServerFilter{})
1323→	installedSet := make(map[string]bool, len(installed))
1324→	for _, srv := range installed {
1325→		if srv.RegistryId != nil {
1326→			installedSet[*srv.RegistryId] = true
1327→		}
1328→	}
1329→
1330→	// Group registry entries by name, collecting versions. The registry
1331→	// returns entries in release order, so we preserve that ordering and
1332→	// then reverse to get most-recent-first.
1333→	type grouped struct {
1334→		order       int
1335→		description string
1336→		versions    []api.MarketplaceServerVersion
1337→	}
1338→	byName := make(map[string]*grouped)
1339→	var insertOrder int
1340→	for _, srv := range servers {
1341→		ver := api.MarketplaceServerVersion{
1342→			Version: srv.Version,
1343→		}
1344→		var envVars []api.RequiredEnvVar
1345→		for _, pkg := range srv.Packages {
1346→			for _, ev := range pkg.EnvVars {
1347→				envVars = append(envVars, api.RequiredEnvVar{
1348→					Name:        ev.Name,
1349→					Description: &ev.Description,
1350→					Required:    &ev.Required,
1351→				})
1352→			}
1353→		}
1354→		if len(envVars) > 0 {
1355→			ver.RequiredEnvVars = &envVars
1356→		}
1357→
1358→		if g, ok := byName[srv.Name]; ok {
1359→			g.versions = append(g.versions, ver)
1360→			// Keep the most recent description (last entry).
1361→			if srv.Description != "" {
1362→				g.description = srv.Description
1363→			}
1364→		} else {
1365→			byName[srv.Name] = &grouped{
1366→				order:       insertOrder,
1367→				description: srv.Description,
1368→				versions:    []api.MarketplaceServerVersion{ver},
1369→			}
1370→			insertOrder++
1371→		}
1372→	}
1373→
1374→	// Build response items sorted by first-seen order.
1375→	items := make([]api.MarketplaceServer, 0, len(byName))
1376→	for name, g := range byName {
1377→		// Reverse versions so most recent is first.
1378→		for i, j := 0, len(g.versions)-1; i < j; i, j = i+1, j-1 {
1379→			g.versions[i], g.versions[j] = g.versions[j], g.versions[i]
1380→		}
1381→		ms := api.MarketplaceServer{
1382→			RegistryId: name,
1383→			Name:       name,
1384→		}
1385→		if g.description != "" {
1386→			ms.Description = &g.description
1387→		}
1388→		isInstalled := installedSet[name]
1389→		ms.Installed = &isInstalled
1390→		ms.Versions = &g.versions
1391→		items = append(items, ms)
1392→	}
1393→	// Stable sort by insertion order.
1394→	sort.Slice(items, func(i, j int) bool {
1395→		return byName[items[i].Name].order < byName[items[j].Name].order
1396→	})
1397→
1398→	writeJSON(w, http.StatusOK, map[string]any{"items": items})
1399→}
1400→
1401→func (s *apiServer) InstallMarketplaceServer(w http.ResponseWriter, r *http.Request, registryId string) {
1402→	ctx := r.Context()
1403→
1404→	srv, err := s.registryClient.Get(ctx, registryId)
1405→	if err != nil {
1406→		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
1407→		return
1408→	}
1409→	if srv == nil {
1410→		writeError(w, http.StatusNotFound, "not_found", "server not found in registry: "+registryId)
1411→		return
1412→	}
1413→
1414→	// Derive command from the best available package.
1415→	command, envVars := deriveCommand(srv)
1416→
1417→	id := "mcp_" + s.newID()
1418→	now := time.Now().UTC()
1419→	stopped := api.MCPServerConfigStatusStopped
1420→	local := api.Local
1421→	config := api.MCPServerConfig{
1422→		Id:         &id,
1423→		Name:       srv.Name,
1424→		Command:    command,
1425→		Status:     &stopped,
1426→		Mode:       &local,
1427→		RegistryId: &registryId,
1428→		CreatedAt:  &now,
1429→	}
1430→	if srv.Description != "" {
1431→		config.Description = &srv.Description
1432→	}
1433→	if srv.Version != "" {
1434→		config.Version = &srv.Version
1435→	}
1436→
1437→	// Pre-populate env map with empty values for required env vars.
1438→	if len(envVars) > 0 {
1439→		envMap := make(map[string]string, len(envVars))
1440→		for _, ev := range envVars {
1441→			envMap[ev.Name] = ""
1442→		}
1443→		config.Env = &envMap
1444→	}
1445→
1446→	if err := s.mcpServers.Create(ctx, config); err != nil {
1447→		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
1448→		return
1449→	}
1450→
1451→	// Build required credentials list.
1452→	var reqCreds []api.RequiredEnvVar
1453→	for _, ev := range envVars {
1454→		reqCreds = append(reqCreds, api.RequiredEnvVar{
1455→			Name:        ev.Name,
1456→			Description: &ev.Description,
1457→			Required:    &ev.Required,
1458→		})
1459→	}
1460→
1461→	result := api.InstallResult{
1462→		Server: config,
1463→	}
1464→	if len(reqCreds) > 0 {
1465→		result.RequiredCredentials = &reqCreds
1466→	}
1467→
1468→	writeJSON(w, http.StatusCreated, result)
1469→}
1470→
1471→// deriveCommand picks the best package from a registry server and returns
1472→// the command array and required env vars.
1473→func deriveCommand(srv *registry.RegistryServer) ([]string, []registry.EnvVar) {
1474→	// Prefer npm packages (most common for MCP servers).
1475→	for _, pkg := range srv.Packages {
1476→		if pkg.RegistryType == "npm" {
1477→			cmd := []string{"npx", "-y", pkg.Name}
1478→			if pkg.Runtime.Args != nil {
1479→				cmd = append(cmd, pkg.Runtime.Args...)
1480→			}
1481→			return cmd, pkg.EnvVars
1482→		}
1483→	}
1484→
1485→	// Fall back to any package with a runtime command.
1486→	for _, pkg := range srv.Packages {
1487→		if pkg.Runtime.Command != "" {
1488→			cmd := []string{pkg.Runtime.Command}
1489→			cmd = append(cmd, pkg.Runtime.Args...)
1490→			return cmd, pkg.EnvVars
1491→		}
1492→	}
1493→
1494→	// Last resort: use the server name as the command.
1495→	return []string{srv.Name}, nil
1496→}
