  1→package registry
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"log/slog"
  8→	"net/http"
  9→	"net/url"
 10→	"strings"
 11→	"sync"
 12→	"time"
 13→)
 14→
 15→const (
 16→	// DefaultRegistryURL is the official MCP Registry API endpoint.
 17→	DefaultRegistryURL = "https://registry.modelcontextprotocol.io"
 18→
 19→	// DefaultRefreshInterval is how often the registry server list is
 20→	// refreshed in the background. Override with REGISTRY_REFRESH_INTERVAL.
 21→	DefaultRefreshInterval = 15 * time.Minute
 22→)
 23→
 24→// Client fetches and caches MCP server metadata from the official registry.
 25→// Call Start to begin the background refresh loop and prefetch on startup.
 26→type Client struct {
 27→	baseURL         string
 28→	httpClient      *http.Client
 29→	refreshInterval time.Duration
 30→	log             *slog.Logger
 31→
 32→	mu     sync.RWMutex
 33→	cached []RegistryServer
 34→
 35→	// ready is closed once the first prefetch completes (success or failure).
 36→	// FetchAll blocks on this so callers see results rather than empty data.
 37→	ready   chan struct{}
 38→	started bool
 39→}
 40→
 41→// NewClient creates a registry client with sensible defaults.
 42→func NewClient(httpClient *http.Client, log *slog.Logger) *Client {
 43→	if httpClient == nil {
 44→		httpClient = &http.Client{Timeout: 30 * time.Second}
 45→	}
 46→	if log == nil {
 47→		log = slog.Default()
 48→	}
 49→	return &Client{
 50→		baseURL:         DefaultRegistryURL,
 51→		httpClient:      httpClient,
 52→		refreshInterval: DefaultRefreshInterval,
 53→		log:             log,
 54→		ready:           make(chan struct{}),
 55→	}
 56→}
 57→
 58→// WithBaseURL overrides the registry URL (useful for testing).
 59→func (c *Client) WithBaseURL(url string) *Client {
 60→	c.baseURL = url
 61→	return c
 62→}
 63→
 64→// WithRefreshInterval overrides the background refresh interval.
 65→func (c *Client) WithRefreshInterval(d time.Duration) *Client {
 66→	c.refreshInterval = d
 67→	return c
 68→}
 69→
 70→// Start prefetches the registry and starts a background goroutine that
 71→// refreshes the cache at the configured interval. The goroutine stops
 72→// when ctx is cancelled.
 73→func (c *Client) Start(ctx context.Context) {
 74→	c.started = true
 75→	go func() {
 76→		// Prefetch asynchronously so the server can start accepting
 77→		// requests immediately. Marketplace queries block on c.ready
 78→		// until this completes.
 79→		if err := c.refresh(ctx); err != nil {
 80→			c.log.Warn("registry prefetch failed; will retry on next interval", "error", err)
 81→		} else {
 82→			c.mu.RLock()
 83→			count := len(c.cached)
 84→			c.mu.RUnlock()
 85→			c.log.Info("registry prefetch complete", "servers", count)
 86→		}
 87→		close(c.ready)
 88→
 89→		ticker := time.NewTicker(c.refreshInterval)
 90→		defer ticker.Stop()
 91→		for {
 92→			select {
 93→			case <-ctx.Done():
 94→				return
 95→			case <-ticker.C:
 96→				if err := c.refresh(ctx); err != nil {
 97→					c.log.Warn("registry refresh failed", "error", err)
 98→				} else {
 99→					c.mu.RLock()
100→					count := len(c.cached)
101→					c.mu.RUnlock()
102→					c.log.Info("registry refresh complete", "servers", count)
103→				}
104→			}
105→		}
106→	}()
107→}
108→
109→// refresh fetches all servers from the registry and replaces the cache.
110→func (c *Client) refresh(ctx context.Context) error {
111→	servers, err := c.fetchFromRegistry(ctx)
112→	if err != nil {
113→		return err
114→	}
115→	c.mu.Lock()
116→	c.cached = servers
117→	c.mu.Unlock()
118→	return nil
119→}
120→
121→// FetchAll returns every server from the registry cache. If Start was called
122→// and the initial prefetch has not completed yet, it blocks until ready (or
123→// ctx is cancelled). If Start was not called, it fetches on demand.
124→func (c *Client) FetchAll(ctx context.Context) ([]RegistryServer, error) {
125→	if c.started {
126→		// Wait for the initial prefetch to complete.
127→		select {
128→		case <-c.ready:
129→		case <-ctx.Done():
130→			return nil, ctx.Err()
131→		}
132→	} else {
133→		// Start was not called — fetch on demand if cache is empty.
134→		c.mu.RLock()
135→		empty := c.cached == nil
136→		c.mu.RUnlock()
137→		if empty {
138→			if err := c.refresh(ctx); err != nil {
139→				return nil, err
140→			}
141→		}
142→	}
143→
144→	c.mu.RLock()
145→	result := make([]RegistryServer, len(c.cached))
146→	copy(result, c.cached)
147→	c.mu.RUnlock()
148→	return result, nil
149→}
150→
151→// Search filters servers by a case-insensitive substring match on name or description.
152→func (c *Client) Search(ctx context.Context, query string) ([]RegistryServer, error) {
153→	all, err := c.FetchAll(ctx)
154→	if err != nil {
155→		return nil, err
156→	}
157→	if query == "" {
158→		return all, nil
159→	}
160→
161→	q := strings.ToLower(query)
162→	var matches []RegistryServer
163→	for _, srv := range all {
164→		if strings.Contains(strings.ToLower(srv.Name), q) ||
165→			strings.Contains(strings.ToLower(srv.Description), q) {
166→			matches = append(matches, srv)
167→		}
168→	}
169→	return matches, nil
170→}
171→
172→// Get returns a single server by registry ID (name).
173→func (c *Client) Get(ctx context.Context, registryID string) (*RegistryServer, error) {
174→	all, err := c.FetchAll(ctx)
175→	if err != nil {
176→		return nil, err
177→	}
178→	for _, srv := range all {
179→		if srv.Name == registryID {
180→			return &srv, nil
181→		}
182→	}
183→	return nil, nil
184→}
185→
186→// pageSize is the maximum number of servers per page (registry max is 100).
187→const pageSize = 100
188→
189→func (c *Client) fetchFromRegistry(ctx context.Context) ([]RegistryServer, error) {
190→	var all []RegistryServer
191→	var cursor string
192→
193→	for {
194→		page, nextCursor, err := c.fetchPage(ctx, cursor)
195→		if err != nil {
196→			return nil, err
197→		}
198→		all = append(all, page...)
199→		if nextCursor == "" || len(page) == 0 {
200→			break
201→		}
202→		cursor = nextCursor
203→	}
204→	return all, nil
205→}
206→
207→func (c *Client) fetchPage(ctx context.Context, cursor string) ([]RegistryServer, string, error) {
208→	u := c.baseURL + "/v0/servers?limit=" + fmt.Sprintf("%d", pageSize)
209→	if cursor != "" {
210→		u += "&cursor=" + url.QueryEscape(cursor)
211→	}
212→
213→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, u, nil)
214→	if err != nil {
215→		return nil, "", fmt.Errorf("registry: create request: %w", err)
216→	}
217→	req.Header.Set("Accept", "application/json")
218→
219→	resp, err := c.httpClient.Do(req)
220→	if err != nil {
221→		return nil, "", fmt.Errorf("registry: fetch: %w", err)
222→	}
223→	defer resp.Body.Close()
224→
225→	if resp.StatusCode != http.StatusOK {
226→		return nil, "", fmt.Errorf("registry: unexpected status %d", resp.StatusCode)
227→	}
228→
229→	var result RegistryResponse
230→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
231→		return nil, "", fmt.Errorf("registry: decode: %w", err)
232→	}
233→
234→	servers := make([]RegistryServer, len(result.Servers))
235→	for i, entry := range result.Servers {
236→		servers[i] = entry.Server
237→	}
238→
239→	var nextCursor string
240→	if result.Metadata != nil {
241→		nextCursor = result.Metadata.NextCursor
242→	}
243→	return servers, nextCursor, nil
244→}
