 53→// forwardToDownstream will fail, but policy interception tests don't need
 54→// downstream forwarding to succeed.
 55→func addFakeRoute(g *gateway, qualifiedName, serverName, originalName, toolPrefix string) {
 56→	g.routes[qualifiedName] = toolRoute{
