 66→func TestRouteToolCall_PolicyAllow(t *testing.T) {
 67→	// Use a capturing engine to verify the allow path is taken and
 68→	// audit events are emitted. We can't forward to a nil client,
 69→	// so we verify via audit events that the "forwarded" event fires.
 70→	var captured policy.EvaluationRequest
 71→	pe := &capturingPolicyEngine{
 72→		decision: model.Decision{
 73→			Disposition: model.DispositionAllow,
 74→			RiskLevel:   model.RiskLevelLow,
 75→		},
 76→		captured: &captured,
 77→	}
 78→	gw := testGateway(t, pe)
 79→	addFakeRoute(gw, "fs__read_file", "fs", "read_file", "filesystem")
 80→	store := gw.auditStore.(*memAuditStore)
 81→
 82→	ctx := context.Background()
 83→	_ = gw.routeToolCall(ctx, "fs__read_file", map[string]any{"path": "/tmp/test"})
 84→
 85→	// Verify policy was evaluated.
 86→	if captured.Action.Type != "filesystem.read_file" {
 87→		t.Errorf("Action.Type = %q, want %q", captured.Action.Type, "filesystem.read_file")
 88→	}
 89→
 90→	// Verify audit events: intercepted + forwarded.
 91→	store.mu.RLock()
 92→	defer store.mu.RUnlock()
 93→	if len(store.events) < 2 {
 94→		t.Fatalf("expected at least 2 audit events, got %d", len(store.events))
 95→	}
 96→	if store.events[0].EventType != model.EventTypeToolCallIntercepted {
 97→		t.Errorf("event[0] = %q, want intercepted", store.events[0].EventType)
 98→	}
 99→	if store.events[1].EventType != model.EventTypeToolCallForwarded {
100→		t.Errorf("event[1] = %q, want forwarded", store.events[1].EventType)
101→	}
102→}
