 1→package auth
 2→
 3→import (
 4→	"context"
 5→	"net/http"
 6→	"strings"
 7→)
 8→
 9→type authContextKey int
10→
11→const (
12→	claimsKey authContextKey = iota
13→)
14→
15→// ClaimsFromContext returns the authenticated claims from the request context,
16→// or nil if the request is not authenticated.
17→func ClaimsFromContext(ctx context.Context) *Claims {
18→	c, _ := ctx.Value(claimsKey).(*Claims)
19→	return c
20→}
21→
22→// ContextWithClaims returns a context with the given claims attached.
23→func ContextWithClaims(ctx context.Context, claims *Claims) context.Context {
24→	return context.WithValue(ctx, claimsKey, claims)
25→}
26→
27→// Middleware returns HTTP middleware that validates Bearer JWTs and injects
28→// claims into the request context. Requests to paths in skipPaths bypass
29→// authentication (e.g. health checks, auth callbacks).
30→func Middleware(issuer *TokenIssuer, skipPaths map[string]bool) func(http.Handler) http.Handler {
31→	return func(next http.Handler) http.Handler {
32→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
33→			// Skip auth for explicitly excluded paths.
34→			if skipPaths[r.URL.Path] {
35→				next.ServeHTTP(w, r)
36→				return
37→			}
38→
39→			// Skip auth for auth routes (prefix match).
40→			if strings.HasPrefix(r.URL.Path, "/auth/") {
41→				next.ServeHTTP(w, r)
42→				return
43→			}
44→
45→			token := extractBearerToken(r)
46→			if token == "" {
47→				http.Error(w, `{"error":"missing or invalid Authorization header"}`, http.StatusUnauthorized)
48→				return
49→			}
50→
51→			claims, err := issuer.Validate(token)
52→			if err != nil {
53→				http.Error(w, `{"error":"invalid or expired token"}`, http.StatusUnauthorized)
54→				return
55→			}
56→
57→			ctx := context.WithValue(r.Context(), claimsKey, claims)
58→			next.ServeHTTP(w, r.WithContext(ctx))
59→		})
60→	}
61→}
62→
63→// extractBearerToken extracts the token from the Authorization header.
64→// It also checks for the access_token cookie as a fallback for browser flows.
65→func extractBearerToken(r *http.Request) string {
66→	auth := r.Header.Get("Authorization")
67→	if strings.HasPrefix(auth, "Bearer ") {
68→		return strings.TrimPrefix(auth, "Bearer ")
69→	}
70→	// Fallback: check cookie for browser-based flows.
71→	if c, err := r.Cookie("access_token"); err == nil {
72→		return c.Value
73→	}
74→	return ""
75→}
76→

  1→package app
  2→
  3→import (
  4→	"net/http"
  5→	"time"
  6→
  7→	api "github.com/ALRubinger/aileron/core/api/gen"
  8→	"github.com/ALRubinger/aileron/core/auth"
  9→	"github.com/ALRubinger/aileron/core/model"
 10→	openapi_types "github.com/oapi-codegen/runtime/types"
 11→)
 12→
 13→// GetCurrentEnterprise and GetCurrentUser are generated ServerInterface
 14→// methods for the Enterprises and Users tags. Auth endpoints (Auth tag)
 15→// are excluded from code generation and handled by core/auth.Handler.
 16→
 17→func (s *apiServer) GetCurrentEnterprise(w http.ResponseWriter, r *http.Request) {
 18→	claims := auth.ClaimsFromContext(r.Context())
 19→	if claims == nil {
 20→		http.Error(w, `{"error":"not authenticated"}`, http.StatusUnauthorized)
 21→		return
 22→	}
 23→
 24→	if s.enterprises == nil {
 25→		http.Error(w, `{"error":"auth not enabled"}`, http.StatusNotImplemented)
 26→		return
 27→	}
 28→
 29→	ent, err := s.enterprises.Get(r.Context(), claims.EnterpriseID)
 30→	if err != nil {
 31→		http.Error(w, `{"error":"enterprise not found"}`, http.StatusNotFound)
 32→		return
 33→	}
 34→	writeJSON(w, http.StatusOK, enterpriseToAPI(ent))
 35→}
 36→
 37→func (s *apiServer) GetCurrentUser(w http.ResponseWriter, r *http.Request) {
 38→	claims := auth.ClaimsFromContext(r.Context())
 39→	if claims == nil {
 40→		http.Error(w, `{"error":"not authenticated"}`, http.StatusUnauthorized)
 41→		return
 42→	}
 43→
 44→	if s.users == nil {
 45→		http.Error(w, `{"error":"auth not enabled"}`, http.StatusNotImplemented)
 46→		return
 47→	}
 48→
 49→	user, err := s.users.Get(r.Context(), claims.Subject)
 50→	if err != nil {
 51→		http.Error(w, `{"error":"user not found"}`, http.StatusNotFound)
 52→		return
 53→	}
 54→	writeJSON(w, http.StatusOK, userToAPI(user))
 55→}
 56→
 57→func (s *apiServer) UpdateCurrentUser(w http.ResponseWriter, r *http.Request) {
 58→	claims := auth.ClaimsFromContext(r.Context())
 59→	if claims == nil {
 60→		writeError(w, http.StatusUnauthorized, "unauthorized", "not authenticated")
 61→		return
 62→	}
 63→
 64→	if s.users == nil {
 65→		writeError(w, http.StatusNotImplemented, "not_implemented", "auth not enabled")
 66→		return
 67→	}
 68→
 69→	var req api.UpdateUserRequest
 70→	if err := decodeBody(r, &req); err != nil {
 71→		writeError(w, http.StatusBadRequest, "bad_request", "invalid request body")
 72→		return
 73→	}
 74→
 75→	user, err := s.users.Get(r.Context(), claims.Subject)
 76→	if err != nil {
 77→		writeError(w, http.StatusNotFound, "not_found", "user not found")
 78→		return
 79→	}
 80→
 81→	if req.DisplayName != nil {
 82→		user.DisplayName = *req.DisplayName
 83→	}
 84→
 85→	user.UpdatedAt = time.Now().UTC()
 86→	if err := s.users.Update(r.Context(), user); err != nil {
 87→		writeError(w, http.StatusInternalServerError, "internal", "failed to update user")
 88→		return
 89→	}
 90→
 91→	writeJSON(w, http.StatusOK, userToAPI(user))
 92→}
 93→
 94→func (s *apiServer) UpdateCurrentEnterprise(w http.ResponseWriter, r *http.Request) {
 95→	claims := auth.ClaimsFromContext(r.Context())
 96→	if claims == nil {
 97→		writeError(w, http.StatusUnauthorized, "unauthorized", "not authenticated")
 98→		return
 99→	}
100→
101→	if s.enterprises == nil {
102→		writeError(w, http.StatusNotImplemented, "not_implemented", "auth not enabled")
103→		return
