13→// Claims are the JWT claims issued by Aileron after authentication.
14→type Claims struct {
15→	jwt.RegisteredClaims
16→	EnterpriseID string `json:"ent_id"`
17→	Email        string `json:"email"`
18→	Role         string `json:"role"`
19→}
20→
21→// TokenIssuer creates and validates JWTs.
22→type TokenIssuer struct {
23→	signingKey []byte
24→	issuer     string
25→	accessTTL  time.Duration
26→}
27→
28→// NewTokenIssuer creates a token issuer with the given HMAC signing key.
29→func NewTokenIssuer(signingKey []byte, issuer string, accessTTL time.Duration) *TokenIssuer {
30→	return &TokenIssuer{
31→		signingKey: signingKey,
32→		issuer:     issuer,
33→		accessTTL:  accessTTL,
34→	}
35→}
36→
37→// Issue creates a signed JWT for the given user.
38→func (ti *TokenIssuer) Issue(userID, enterpriseID, email, role string) (string, error) {
39→	now := time.Now()
40→	claims := Claims{
41→		RegisteredClaims: jwt.RegisteredClaims{
42→			Subject:   userID,
43→			Issuer:    ti.issuer,
44→			IssuedAt:  jwt.NewNumericDate(now),
45→			ExpiresAt: jwt.NewNumericDate(now.Add(ti.accessTTL)),
46→		},
47→		EnterpriseID: enterpriseID,
48→		Email:        email,
49→		Role:         role,
50→	}
51→
52→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
53→	return token.SignedString(ti.signingKey)
54→}
55→
56→// Validate parses and validates a JWT, returning the claims.
57→func (ti *TokenIssuer) Validate(tokenString string) (*Claims, error) {
58→	token, err := jwt.ParseWithClaims(tokenString, &Claims{}, func(t *jwt.Token) (any, error) {
59→		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
60→			return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
61→		}
62→		return ti.signingKey, nil
63→	})
64→	if err != nil {
65→		return nil, fmt.Errorf("invalid token: %w", err)
66→	}
67→
68→	claims, ok := token.Claims.(*Claims)
69→	if !ok || !token.Valid {
70→		return nil, fmt.Errorf("invalid token claims")
71→	}
72→	return claims, nil
73→}
74→
75→// GenerateRefreshToken creates a cryptographically random refresh token
76→// and returns both the raw token (to send to the client) and its SHA-256
77→// hash (to store in the database).
78→func GenerateRefreshToken() (raw string, hash string, err error) {
79→	b := make([]byte, 32)
80→	if _, err := rand.Read(b); err != nil {
81→		return "", "", fmt.Errorf("generating refresh token: %w", err)
82→	}
83→	raw = hex.EncodeToString(b)
84→	hash = HashToken(raw)
85→	return raw, hash, nil
86→}
87→
88→// HashToken returns the hex-encoded SHA-256 hash of a token string.
89→func HashToken(token string) string {
90→	h := sha256.Sum256([]byte(token))
91→	return hex.EncodeToString(h[:])
92→}
