 54→func (s *UserStore) List(ctx context.Context, filter store.UserFilter) ([]model.User, error) {
 55→	query := `SELECT ` + userColumns + ` FROM users WHERE 1=1`
 56→	args := []any{}
 57→	argIdx := 1
 58→
 59→	if filter.EnterpriseID != "" {
 60→		query += fmt.Sprintf(" AND enterprise_id = $%d", argIdx)
 61→		args = append(args, filter.EnterpriseID)
 62→		argIdx++
 63→	}
 64→	if filter.Status != nil {
 65→		query += fmt.Sprintf(" AND status = $%d", argIdx)
 66→		args = append(args, string(*filter.Status))
 67→		argIdx++
 68→	}
 69→
 70→	query += " ORDER BY created_at ASC"
 71→
 72→	if filter.PageSize > 0 {
 73→		query += fmt.Sprintf(" LIMIT $%d", argIdx)
 74→		args = append(args, filter.PageSize)
 75→	}
 76→
 77→	rows, err := s.db.Pool.Query(ctx, query, args...)
 78→	if err != nil {
 79→		return nil, err
 80→	}
 81→	defer rows.Close()
 82→
 83→	var users []model.User
 84→	for rows.Next() {
 85→		u, err := scanUser(rows)
 86→		if err != nil {
 87→			return nil, err
 88→		}
 89→		users = append(users, u)
 90→	}
 91→	return users, rows.Err()
 92→}
