 94→func (s *UserStore) Update(ctx context.Context, u model.User) error {
 95→	tag, err := s.db.Pool.Exec(ctx,
 96→		`UPDATE users
 97→		 SET enterprise_id=$2, email=$3, display_name=$4, avatar_url=$5, role=$6,
 98→			 status=$7, auth_provider=$8, auth_provider_subject_id=$9,
 99→			 password_hash=$10, last_login_at=$11, updated_at=$12
100→		 WHERE id=$1`,
101→		u.ID, u.EnterpriseID, u.Email, u.DisplayName, u.AvatarURL,
102→		string(u.Role), string(u.Status), u.AuthProvider, u.AuthProviderSubjectID,
103→		u.PasswordHash, u.LastLoginAt, u.UpdatedAt,
104→	)
105→	if err != nil {
106→		return err
107→	}
108→	if tag.RowsAffected() == 0 {
109→		return &store.ErrNotFound{Entity: "user", ID: u.ID}
110→	}
111→	return nil
112→}
113→
114→func (s *UserStore) scanOne(ctx context.Context, query string, args ...any) (model.User, error) {
115→	row := s.db.Pool.QueryRow(ctx, query, args...)
116→	var u model.User
117→	var role, status string
118→	err := row.Scan(
119→		&u.ID, &u.EnterpriseID, &u.Email, &u.DisplayName, &u.AvatarURL,
120→		&role, &status, &u.AuthProvider, &u.AuthProviderSubjectID,
121→		&u.PasswordHash, &u.LastLoginAt, &u.CreatedAt, &u.UpdatedAt,
122→	)
123→	if err != nil {
124→		if err == pgx.ErrNoRows {
125→			return model.User{}, &store.ErrNotFound{Entity: "user", ID: fmt.Sprint(args...)}
126→		}
127→		return model.User{}, err
128→	}
129→	u.Role = model.UserRole(role)
130→	u.Status = model.UserStatus(status)
131→	return u, nil
132→}
133→
134→// scanUser scans a user from a pgx.Rows iterator.
135→func scanUser(rows pgx.Rows) (model.User, error) {
136→	var u model.User
137→	var role, status string
138→	err := rows.Scan(
139→		&u.ID, &u.EnterpriseID, &u.Email, &u.DisplayName, &u.AvatarURL,
140→		&role, &status, &u.AuthProvider, &u.AuthProviderSubjectID,
141→		&u.PasswordHash, &u.LastLoginAt, &u.CreatedAt, &u.UpdatedAt,
142→	)
143→	if err != nil {
144→		return model.User{}, err
145→	}
146→	u.Role = model.UserRole(role)
147→	u.Status = model.UserStatus(status)
148→	return u, nil
149→}
