1275→		Type: "mcp_server_credential",
1276→		Labels: map[string]string{
1277→			"server_id": id,
1278→			"env_var":   req.EnvVarName,
1279→		},
1280→	})
1281→
1282→	// Update server config env to reference the vault path.
1283→	envMap := make(map[string]string)
1284→	if srv.Env != nil {
1285→		for k, v := range *srv.Env {
1286→			envMap[k] = v
1287→		}
1288→	}
1289→	envMap[req.EnvVarName] = "vault://" + vaultPath
1290→	srv.Env = &envMap
1291→	now := time.Now().UTC()
1292→	srv.UpdatedAt = &now
1293→
1294→	if err := s.mcpServers.Update(ctx, srv); err != nil {
1295→		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
1296→		return
1297→	}
1298→
1299→	writeJSON(w, http.StatusOK, api.SetCredentialResponse{
1300→		EnvVarName: req.EnvVarName,
1301→		Stored:     true,
1302→	})
1303→}
