1306→
1307→func (s *apiServer) ListMarketplaceServers(w http.ResponseWriter, r *http.Request, params api.ListMarketplaceServersParams) {
1308→	ctx := r.Context()
1309→
1310→	var query string
1311→	if params.Q != nil {
1312→		query = *params.Q
1313→	}
1314→
1315→	servers, err := s.registryClient.Search(ctx, query)
1316→	if err != nil {
1317→		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
1318→		return
1319→	}
1320→
1321→	// Build a set of installed registry IDs for enrichment.
1322→	installed, _ := s.mcpServers.List(ctx, store.MCPServerFilter{})
1323→	installedSet := make(map[string]bool, len(installed))
1324→	for _, srv := range installed {
1325→		if srv.RegistryId != nil {
1326→			installedSet[*srv.RegistryId] = true
1327→		}
1328→	}
1329→
1330→	// Group registry entries by name, collecting versions. The registry
1331→	// returns entries in release order, so we preserve that ordering and
1332→	// then reverse to get most-recent-first.
1333→	type grouped struct {
1334→		order       int
1335→		description string
1336→		versions    []api.MarketplaceServerVersion
1337→	}
1338→	byName := make(map[string]*grouped)
1339→	var insertOrder int
1340→	for _, srv := range servers {
1341→		ver := api.MarketplaceServerVersion{
1342→			Version: srv.Version,
1343→		}
1344→		var envVars []api.RequiredEnvVar
1345→		for _, pkg := range srv.Packages {
1346→			for _, ev := range pkg.EnvVars {
1347→				envVars = append(envVars, api.RequiredEnvVar{
1348→					Name:        ev.Name,
1349→					Description: &ev.Description,
1350→					Required:    &ev.Required,
1351→				})
1352→			}
1353→		}
1354→		if len(envVars) > 0 {
1355→			ver.RequiredEnvVars = &envVars
1356→		}
1357→
1358→		if g, ok := byName[srv.Name]; ok {
1359→			g.versions = append(g.versions, ver)
1360→			// Keep the most recent description (last entry).
1361→			if srv.Description != "" {
1362→				g.description = srv.Description
1363→			}
1364→		} else {
1365→			byName[srv.Name] = &grouped{
1366→				order:       insertOrder,
1367→				description: srv.Description,
1368→				versions:    []api.MarketplaceServerVersion{ver},
1369→			}
1370→			insertOrder++
1371→		}
1372→	}
1373→
1374→	// Build response items sorted by first-seen order.
1375→	items := make([]api.MarketplaceServer, 0, len(byName))
1376→	for name, g := range byName {
1377→		// Reverse versions so most recent is first.
1378→		for i, j := 0, len(g.versions)-1; i < j; i, j = i+1, j-1 {
1379→			g.versions[i], g.versions[j] = g.versions[j], g.versions[i]
1380→		}
1381→		ms := api.MarketplaceServer{
1382→			RegistryId: name,
1383→			Name:       name,
1384→		}
1385→		if g.description != "" {
1386→			ms.Description = &g.description
1387→		}
1388→		isInstalled := installedSet[name]
1389→		ms.Installed = &isInstalled
1390→		ms.Versions = &g.versions
1391→		items = append(items, ms)
1392→	}
1393→	// Stable sort by insertion order.
1394→	sort.Slice(items, func(i, j int) bool {
1395→		return byName[items[i].Name].order < byName[items[j].Name].order
1396→	})
1397→
1398→	writeJSON(w, http.StatusOK, map[string]any{"items": items})
1399→}
