 6→	"strings"
 7→)
 8→
 9→type authContextKey int
10→
11→const (
12→	claimsKey authContextKey = iota
13→)
14→
15→// ClaimsFromContext returns the authenticated claims from the request context,
16→// or nil if the request is not authenticated.
17→func ClaimsFromContext(ctx context.Context) *Claims {
18→	c, _ := ctx.Value(claimsKey).(*Claims)
19→	return c
20→}
21→
22→// ContextWithClaims returns a context with the given claims attached.
23→func ContextWithClaims(ctx context.Context, claims *Claims) context.Context {
24→	return context.WithValue(ctx, claimsKey, claims)
25→}
26→
27→// Middleware returns HTTP middleware that validates Bearer JWTs and injects
28→// claims into the request context. Requests to paths in skipPaths bypass
29→// authentication (e.g. health checks, auth callbacks).
30→func Middleware(issuer *TokenIssuer, skipPaths map[string]bool) func(http.Handler) http.Handler {
31→	return func(next http.Handler) http.Handler {
32→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
33→			// Skip auth for explicitly excluded paths.
34→			if skipPaths[r.URL.Path] {
35→				next.ServeHTTP(w, r)
36→				return
37→			}
38→
39→			// Skip auth for auth routes (prefix match).
40→			if strings.HasPrefix(r.URL.Path, "/auth/") {
41→				next.ServeHTTP(w, r)
42→				return
43→			}
44→
45→			token := extractBearerToken(r)
46→			if token == "" {
47→				http.Error(w, `{"error":"missing or invalid Authorization header"}`, http.StatusUnauthorized)
48→				return
49→			}
50→
51→			claims, err := issuer.Validate(token)
52→			if err != nil {
53→				http.Error(w, `{"error":"invalid or expired token"}`, http.StatusUnauthorized)
54→				return
55→			}
56→
57→			ctx := context.WithValue(r.Context(), claimsKey, claims)
58→			next.ServeHTTP(w, r.WithContext(ctx))
59→		})
60→	}
61→}
62→
63→// extractBearerToken extracts the token from the Authorization header.
64→// It also checks for the access_token cookie as a fallback for browser flows.
65→func extractBearerToken(r *http.Request) string {
66→	auth := r.Header.Get("Authorization")
67→	if strings.HasPrefix(auth, "Bearer ") {
68→		return strings.TrimPrefix(auth, "Bearer ")
69→	}
70→	// Fallback: check cookie for browser-based flows.
71→	if c, err := r.Cookie("access_token"); err == nil {
72→		return c.Value
73→	}
74→	return ""
75→}
