 4→const API_BASE = PUBLIC_API_BASE;
 5→
 6→async function apiFetch(path: string, options?: RequestInit) {
 7→	const headers: Record<string, string> = {
 8→		'Content-Type': 'application/json',
 9→		...Object.fromEntries(new Headers(options?.headers).entries())
10→	};
11→
12→	const token = getToken();
13→	if (token && token !== 'cookie-auth') {
14→		headers['Authorization'] = `Bearer ${token}`;
15→	}
16→
17→	let res = await fetch(`${API_BASE}${path}`, { ...options, headers, credentials: 'include' });
18→
19→	// If unauthorized, attempt token refresh and retry once.
20→	if (res.status === 401 && token) {
21→		const refreshed = await refreshAuth();
22→		if (refreshed) {
23→			const newToken = getToken();
24→			if (newToken) {
25→				headers['Authorization'] = `Bearer ${newToken}`;
26→			}
27→			res = await fetch(`${API_BASE}${path}`, { ...options, headers, credentials: 'include' });
28→		} else {
29→			clearAuth();
30→			if (typeof window !== 'undefined') {
31→				window.location.href = '/login';
32→			}
33→			throw new Error('Session expired');
34→		}
35→	}
36→
37→	if (res.status === 204) return null;
38→	if (!res.ok) {
39→		const err = await res.json().catch(() => ({ error: { message: res.statusText } }));
40→		throw new Error(err.error?.message || res.statusText);
41→	}
42→	return res.json();
43→}
