 92→/** Fetch the current user profile from /v1/users/me. */
 93→async function fetchCurrentUser() {
 94→	const headers: Record<string, string> = {};
 95→	// Use Bearer token for password-based auth; use cookies for OAuth flow.
 96→	if (_token && _token !== 'cookie-auth') {
 97→		headers['Authorization'] = `Bearer ${_token}`;
 98→	}
 99→	const res = await fetch(`${PUBLIC_API_BASE}/v1/users/me`, {
100→		headers,
101→		credentials: 'include'
102→	});
103→	if (!res.ok) throw new Error('Failed to fetch user');
104→	_user = await res.json();
105→}
