  1→<script lang="ts">
  2→	import { page } from '$app/stores';
  3→	import { goto } from '$app/navigation';
  4→	import { getMCPServer, deleteMCPServer, setMCPServerCredential } from '$lib/api';
  5→	import { onMount } from 'svelte';
  6→	import { serverStatusColor, modeColor } from '$lib/colors';
  7→	import * as Card from '$lib/components/ui/card';
  8→	import { Button } from '$lib/components/ui/button';
  9→	import { Input } from '$lib/components/ui/input';
 10→
 11→	let server = $state<any>(null);
 12→	let loading = $state(true);
 13→	let error = $state('');
 14→	let deleting = $state(false);
 15→
 16→	let credEnvVar = $state('');
 17→	let credValue = $state('');
 18→	let credSaving = $state(false);
 19→	let credResult = $state('');
 20→
 21→	let id = $derived($page.params.id ?? '');
 22→
 23→	async function load() {
 24→		try {
 25→			server = await getMCPServer(id);
 26→		} catch (e: any) {
 27→			error = e.message;
 28→		} finally {
 29→			loading = false;
 30→		}
 31→	}
 32→
 33→	onMount(() => {
 34→		load();
 35→	});
 36→
 37→	async function handleSetCredential() {
 38→		if (!credEnvVar.trim() || !credValue.trim()) return;
 39→		credSaving = true;
 40→		credResult = '';
 41→		try {
 42→			await setMCPServerCredential(id, credEnvVar.trim(), credValue);
 43→			credResult = `Stored ${credEnvVar.trim()} in vault.`;
 44→			credEnvVar = '';
 45→			credValue = '';
 46→			await load();
 47→		} catch (e: any) {
 48→			credResult = `Error: ${e.message}`;
 49→		} finally {
 50→			credSaving = false;
 51→		}
 52→	}
 53→
 54→	async function handleDelete() {
 55→		if (!confirm(`Remove server "${server?.name}"? This cannot be undone.`)) return;
 56→		deleting = true;
 57→		try {
 58→			await deleteMCPServer(id);
 59→			goto('/servers');
 60→		} catch (e: any) {
 61→			error = e.message;
 62→			deleting = false;
 63→		}
 64→	}
 65→</script>
 66→
 67→<svelte:head>
 68→	<title>{server?.name || 'Server'} - Aileron</title>
 69→</svelte:head>
 70→
 71→<a href="/servers" class="text-muted-foreground no-underline text-sm">&larr; Back to Servers</a>
 72→
 73→{#if loading}
 74→	<p class="text-muted-foreground mt-4">Loading...</p>
 75→{:else if error}
 76→	<p class="text-destructive mt-4">{error}</p>
 77→{:else if server}
