 82→		{/if}
 83→		<span class="rounded border px-2 py-0.5 text-xs font-semibold uppercase" style="color: {serverStatusColor(server.status)}; border-color: {serverStatusColor(server.status)}">
 84→			{server.status || 'stopped'}
 85→		</span>
 86→		<span class="rounded border px-2 py-0.5 text-xs font-semibold uppercase" style="color: {modeColor(server.mode)}; border-color: {modeColor(server.mode)}">
 87→			{server.mode || 'local'}
 88→		</span>
 89→	</div>
 90→
 91→	<Card.Root class="mb-4">
 92→		<Card.Header>
 93→			<Card.Title>Configuration</Card.Title>
 94→		</Card.Header>
 95→		<Card.Content>
 96→			<div class="grid grid-cols-[auto_1fr] gap-x-4 gap-y-1.5 text-sm">
 97→				<span class="text-muted-foreground">ID</span>
 98→				<span class="font-mono">{server.id}</span>
 99→
100→				{#if server.description}
101→					<span class="text-muted-foreground">Description</span>
102→					<span>{server.description}</span>
103→				{/if}
104→
105→				<span class="text-muted-foreground">Command</span>
106→				<span class="font-mono">{(server.command || []).join(' ')}</span>
107→
108→				<span class="text-muted-foreground">Mode</span>
109→				<span>{server.mode || 'local'}</span>
110→
111→				{#if server.version}
112→					<span class="text-muted-foreground">Version</span>
113→					<span>{server.version}</span>
114→				{/if}
115→
116→				{#if server.registry_id}
117→					<span class="text-muted-foreground">Registry ID</span>
118→					<span class="font-mono">{server.registry_id}</span>
119→				{/if}
120→
121→				{#if server.policy_mapping?.tool_prefix}
122→					<span class="text-muted-foreground">Tool Prefix</span>
123→					<span class="font-mono">{server.policy_mapping.tool_prefix}</span>
124→				{/if}
125→
126→				{#if server.created_at}
127→					<span class="text-muted-foreground">Created</span>
128→					<span>{new Date(server.created_at).toLocaleString()}</span>
