150→								<span title={String(value)}>&#128274; vault-backed</span>
151→							{:else}
152→								{value || '(empty)'}
153→							{/if}
154→						</span>
155→					{/each}
156→				</div>
157→			</Card.Content>
158→		</Card.Root>
159→	{/if}
160→
161→	<Card.Root class="mb-4">
162→		<Card.Header>
163→			<Card.Title>Set Credential</Card.Title>
164→			<Card.Description>Store a secret in the vault for this server.</Card.Description>
165→		</Card.Header>
166→		<Card.Content>
167→			<div class="flex gap-2 items-end flex-wrap">
168→				<div>
169→					<label for="cred-env-var" class="block text-xs text-muted-foreground mb-1">Env var name</label>
170→					<Input
171→						id="cred-env-var"
172→						type="text"
173→						bind:value={credEnvVar}
174→						placeholder="e.g. API_KEY"
175→						class="font-mono"
176→					/>
177→				</div>
178→				<div>
179→					<label for="cred-secret" class="block text-xs text-muted-foreground mb-1">Secret value</label>
180→					<Input
181→						id="cred-secret"
182→						type="password"
183→						bind:value={credValue}
184→						placeholder="Enter secret..."
185→					/>
186→				</div>
187→				<Button
188→					onclick={handleSetCredential}
189→					disabled={credSaving}
190→				>
191→					{credSaving ? 'Saving...' : 'Save'}
192→				</Button>
193→			</div>
194→			{#if credResult}
195→				<p class="mt-2 text-xs" style="color: {credResult.startsWith('Error') ? 'var(--color-status-red)' : 'var(--color-status-green)'}">{credResult}</p>
196→			{/if}
197→		</Card.Content>
198→	</Card.Root>
199→
200→	<Card.Root class="border-destructive">
201→		<Card.Header>
202→			<Card.Title class="text-destructive">Danger Zone</Card.Title>
203→		</Card.Header>
204→		<Card.Content>
205→			<Button
206→				variant="destructive"
207→				onclick={handleDelete}
208→				disabled={deleting}
209→			>
210→				{deleting ? 'Removing...' : 'Delete Server'}
