 10→	let enterprise = $state<any>(null);
 11→	let loading = $state(true);
 12→	let saving = $state(false);
 13→	let error = $state('');
 14→	let success = $state('');
 15→
 16→	let name = $state('');
 17→	let billingEmail = $state('');
 18→	let ssoRequired = $state(false);
 19→	let allowedProviders = $state('');
 20→	let allowedDomains = $state('');
 21→
 22→	$effect(() => {
 23→		if (enterprise) {
 24→			name = enterprise.name || '';
 25→			billingEmail = enterprise.billing_email || '';
 26→			ssoRequired = enterprise.sso_required || false;
 27→			allowedProviders = (enterprise.allowed_auth_providers || []).join(', ');
 28→			allowedDomains = (enterprise.allowed_email_domains || []).join(', ');
 29→		}
 30→	});
 31→
 32→	const canEdit = $derived(
 33→		(() => {
 34→			const user = getUser();
 35→			return user?.role === 'owner' || user?.role === 'admin';
 36→		})()
 37→	);
 38→
 39→	onMount(async () => {
 40→		try {
 41→			enterprise = await getCurrentEnterprise();
 42→		} catch (e: any) {
 43→			error = e.message;
 44→		} finally {
 45→			loading = false;
 46→		}
 47→	});
 48→
 49→	function parseList(s: string): string[] {
 50→		return s
 51→			.split(',')
 52→			.map((v) => v.trim())
 53→			.filter(Boolean);
 54→	}
 55→
 56→	async function handleSave() {
 57→		error = '';
 58→		success = '';
 59→		saving = true;
 60→		try {
 61→			enterprise = await updateCurrentEnterprise({
 62→				name,
