 17→)
 18→
 19→func newMCPServer() *apiServer {
 20→	return &apiServer{
 21→		mcpServers:           mem.NewMCPServerStore(),
 22→		enterpriseMCPServers: mem.NewEnterpriseMCPServerStore(),
 23→		vault:                vault.NewMemVault(),
 24→		users:                nil, // auth enabled check: nil means auth disabled
 25→		newID:                func() string { return "test-id" },
 26→	}
 27→}
 28→
 29→func newMCPServerWithAuth() *apiServer {
 30→	srv := newMCPServer()
 31→	// Setting users to non-nil signals auth is enabled, so requireAuth
 32→	// will enforce authentication.
 33→	srv.users = &stubUserStore{}
 34→	return srv
 35→}
 36→
 37→// stubUserStore is a minimal non-nil UserStore to signal auth is enabled.
 38→type stubUserStore struct{}
 39→
 40→func (s *stubUserStore) Create(_ context.Context, _ model.User) error { return nil }
 41→func (s *stubUserStore) Get(_ context.Context, _ string) (model.User, error) {
 42→	return model.User{}, nil
 43→}
 44→func (s *stubUserStore) GetByEmail(_ context.Context, _ string) (model.User, error) {
