// Client fetches and caches MCP server metadata from the official registry.
// Call Start to begin the background refresh loop and prefetch on startup.
type Client struct {
	baseURL         string
	httpClient      *http.Client
	refreshInterval time.Duration
	log             *slog.Logger

	mu     sync.RWMutex
	cached []RegistryServer

	// ready is closed once the first prefetch completes (success or failure).
	// FetchAll blocks on this so callers see results rather than empty data.
	ready   chan struct{}
	started bool
}

// NewClient creates a registry client with sensible defaults.
func NewClient(httpClient *http.Client, log *slog.Logger) *Client {
	if httpClient == nil {
		httpClient = &http.Client{Timeout: 30 * time.Second}
	}
	if log == nil {
		log = slog.Default()
	}
	return &Client{
		baseURL:         DefaultRegistryURL,
		httpClient:      httpClient,
		refreshInterval: DefaultRefreshInterval,
		log:             log,
		ready:           make(chan struct{}),
	}
}

// WithBaseURL overrides the registry URL (useful for testing).
func (c *Client) WithBaseURL(url string) *Client {
	c.baseURL = url
	return c
}

// WithRefreshInterval overrides the background refresh interval.
func (c *Client) WithRefreshInterval(d time.Duration) *Client {
	c.refreshInterval = d
	return c
}

// Package registry provides a client for the official MCP Registry.
package registry

// RegistryResponse is the top-level response from the MCP Registry API.
type RegistryResponse struct {
	Servers  []RegistryEntry  `json:"servers"`
	Metadata *RegistryMetadata `json:"metadata,omitempty"`
}

// RegistryMetadata contains pagination information from the registry.
type RegistryMetadata struct {
	NextCursor string `json:"nextCursor,omitempty"`
	Count      int    `json:"count,omitempty"`
}

// RegistryEntry wraps a server with optional registry metadata.
type RegistryEntry struct {
	Server RegistryServer `json:"server"`
}

// RegistryServer represents a single server entry from the MCP Registry.
type RegistryServer struct {
	// Canonical fields from the registry.
	Name        string    `json:"name"`
	Description string    `json:"description"`
	Repository  *RepoInfo `json:"repository,omitempty"`
	VersionDetail
}

// VersionDetail holds the latest version information for a server.
type VersionDetail struct {
	Version  string    `json:"version"`
	Packages []Package `json:"packages,omitempty"`
	Remotes  []Remote  `json:"remotes,omitempty"`
}

// RepoInfo is the repository metadata for a server.
type RepoInfo struct {
	URL string `json:"url"`
}

// Remote represents a remote (HTTP/SSE) transport endpoint.
type Remote struct {
	TransportType string         `json:"type"`
	URL           string         `json:"url"`
	Headers       []RemoteHeader `json:"headers,omitempty"`
}

// RemoteHeader describes a required HTTP header for a remote endpoint.
type RemoteHeader struct {
	Name        string `json:"name"`
	Description string `json:"description,omitempty"`
	IsRequired  bool   `json:"isRequired,omitempty"`
	IsSecret    bool   `json:"isSecret,omitempty"`
}

// Package represents a distributable package for an MCP server.
type Package struct {
	RegistryType string        `json:"registryType"` // "npm", "pypi", "docker", etc.
	Name         string        `json:"name"`
	Version      string        `json:"version,omitempty"`
	Runtime      RuntimeConfig `json:"runtime"`
	EnvVars      []EnvVar      `json:"environmentVariables,omitempty"`
}

// RuntimeConfig describes how to launch a package.
type RuntimeConfig struct {
	Type    string   `json:"type"`              // "node", "python", "docker"
	Command string   `json:"command,omitempty"` // e.g. "npx"
	Args    []string `json:"args,omitempty"`
}

// EnvVar describes an environment variable required by an MCP server.
type EnvVar struct {
	Name        string `json:"name"`
	Description string `json:"description,omitempty"`
	Required    bool   `json:"required"`
}

